static inline uint32_t AlignDown(uint32_t x, uint32_t a)
{
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b)
{
    return (a + b - 1u) / b;
}

// Conservative UB budget per core; used to select tile sizes.
static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 256;

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    MatmulSumMaxAvgPoolLogSumExpLogSumExpCustomTilingData tiling;

    const gert::Shape* xShape = context->GetInputShape(0);
    const gert::Shape* wShape = context->GetInputShape(1);
    const gert::Shape* bShape = context->GetInputShape(2);

    // Expect x: [M, K], w: [N, K], b: [N]
    uint32_t m = 1, k = 1, n = 1;
    if (xShape->GetOriginShape().GetDimNum() >= 2) {
        m = static_cast<uint32_t>(xShape->GetOriginShape().GetDim(0));
        k = static_cast<uint32_t>(xShape->GetOriginShape().GetDim(1));
    } else {
        // Fallback from total size if dim info unavailable
        uint64_t sz = xShape->GetOriginShape().GetShapeSize();
        k = static_cast<uint32_t>(sz);
        m = 1;
    }
    if (wShape->GetOriginShape().GetDimNum() >= 2) {
        n = static_cast<uint32_t>(wShape->GetOriginShape().GetDim(0));
        // wShape dim(1) should equal k
    } else {
        n = static_cast<uint32_t>(bShape->GetOriginShape().GetShapeSize());
    }

    // Choose tileK and tileRows within UB budget:
    // Buffers (floats) we reserve:
    //  - wsum[K]
    //  - wrow[K] (optional reuse)
    //  - xChunk[tileK]
    //  - mulTmp[tileK]
    //  - yTile[tileRows]
    // Approx bytes = 4*(K + K + tileK + tileK + tileRows)
    // For safety, cap tileK to min(k, 2048) and align to 256.
    uint32_t tileK = k;
    const uint32_t capTileK = 2048u;
    if (tileK > capTileK) tileK = capTileK;
    tileK = AlignDown(tileK, ALIGN_ELEMS);
    if (tileK == 0) tileK = (k < ALIGN_ELEMS ? k : ALIGN_ELEMS);

    // tileRows chosen to keep UB footprint under budget.
    // Estimate UB bytes if we allocate both wsum and wrow: 4*(2*k + 2*tileK + tileRows).
    uint32_t maxTileRows = 0;
    if (4ull * (2ull * k + 2ull * tileK) >= UB_BUDGET_BYTES) {
        maxTileRows = ALIGN_ELEMS; // very conservative fallback
    } else {
        maxTileRows = static_cast<uint32_t>(
            (UB_BUDGET_BYTES - 4u * (2u * k + 2u * tileK)) / 4u
        );
    }
    if (maxTileRows == 0) maxTileRows = ALIGN_ELEMS;
    uint32_t tileRows = maxTileRows;
    if (tileRows > m) tileRows = m;
    tileRows = AlignDown(tileRows, ALIGN_ELEMS);
    if (tileRows == 0) tileRows = (m < ALIGN_ELEMS ? m : ALIGN_ELEMS);

    uint32_t numTiles = CeilDiv(m, tileRows);
    uint32_t blockDim = numTiles;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;
    context->SetBlockDim(blockDim);

    tiling.set_m(m);
    tiling.set_n(n);
    tiling.set_k(k);
    tiling.set_tileRows(tileRows);
    tiling.set_tileK(tileK);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
